    variant: 'primary',
    size: 'md',
    disabled: false,
    loading: false,
    fullWidth: false,
    loadingText: '',
    className: '',
  },
  argTypes: {
    // Appearance
    variant: {
      control: 'select',
      options: [
        'primary',
        'secondary',
        'success',
        'danger',
        'warning',
        'info',
        'light',
        'dark',
        'link',
      ],
      description: 'Visual style variant.',
      table: { category: 'Appearance', defaultValue: { summary: 'primary' } },
    },
    size: {
      control: 'select',
      options: ['sm', 'md', 'lg'],
      description: 'Button size.',
      table: { category: 'Appearance', defaultValue: { summary: 'md' } },
    },
    fullWidth: {
      control: 'boolean',
      description: 'Makes the button span the full width of its container.',
      table: { category: 'Layout', defaultValue: { summary: 'false' } },
    },

    // Behavior
    type: {
      control: 'select',
      options: ['button', 'submit', 'reset'],
      description: 'Native button type attribute.',
      table: { category: 'Behavior', defaultValue: { summary: 'button' } },
    },

    // State
    disabled: {
      control: 'boolean',
      description: 'Disables the button.',
      table: { category: 'State', defaultValue: { summary: 'false' } },
    },
    loading: {
      control: 'boolean',
      description: 'Shows a busy state (spinner) and disables the button.',
      table: { category: 'State', defaultValue: { summary: 'false' } },
    },
    loadingText: {
      control: 'text',
      description: 'Optional label shown while loading. If empty, shows normal content.',
