      if (context?.viewMode === 'docs') {
        return storyFn();
      }

      // ✅ In Canvas (story view), wrap in the Gravitas shell.
      const story = storyFn();

      return {
        ...story,
        moduleMetadata: {
          ...(story.moduleMetadata ?? {}),
          imports: [
            ...((story.moduleMetadata?.imports as any[]) ?? []),
            ShellWrapperComponent,
          ],
        },
        template: `
          <gv-story-shell>
            ${story.template ?? ''}
          </gv-story-shell>
        `,
        props: story.props ?? {},
      };
    },
  ],
}

